-- Relación: Venta -> DetalleVenta (1:N)
IF NOT EXISTS (SELECT * FROM sys.foreign_keys WHERE object_id = OBJECT_ID(N'[dbo].[FK_DetalleVenta_Venta]') AND parent_object_id = OBJECT_ID(N'[dbo].[DetalleVenta]'))
BEGIN
    ALTER TABLE [dbo].[DetalleVenta] ADD CONSTRAINT [FK_DetalleVenta_Venta]
    FOREIGN KEY ([VentaID]) REFERENCES [dbo].[Venta] ([VentaID])
    ON DELETE CASCADE;
